Get-NetTCPConnection -State Established | ForEach-Object { $proc = Get-Process -Id $_.OwningProcess -ErrorAction SilentlyContinue; if ($proc) { $name = $proc.Name.PadRight(25).Substring(0,25); $idStr = $_.OwningProcess.ToString().PadRight(10); $remote = $_.RemoteAddress.ToString().PadRight(20); $port = $_.RemotePort.ToString(); Write-Host ("$name $idStr $remote $port") -ForegroundColor Cyan } }
